                val mask = (1 shl i) or (1 shl j)
                dp[mask][i][j] = true
                dp[mask][j][i] = true
                maxLength = maxLength.coerceAtLeast(2)
            }
        }
    }

    for (mask in 1 until totalMasks) {
        val count = mask.countOneBits()
        for (i in 0 until nInt) {
            for (j in 0 until nInt) {
